#include <bits/stdc++.h>
using namespace std;
int n,m,a[2003],b[2003];
int main(){
	cin>>n;
	for(int i=0;i<n;i++)cin>>a[i];
	cin>>m;
	for(int i=0;i<m;i++){
		cin>>b[i];b[i]=a[b[i]];
		int sum=0;
		for(int j=0;j<i;j++){
		    if(b[j]>b[i]){
		        swap(b[j],b[i]);
		        sum++;
		    }
		}
		cout<<sum<<endl;
	}
	return 0;
}
